123	// ReadAll loads bead rows and event entities from disk and re-merges events
124	// back into each bead's Extra["events"]. Orphan events (event_of pointing at
125	// a missing bead, e.g. after a partial-write crash) are silently dropped.
126	func (a *AxonBackend) ReadAll() ([]Bead, error) {
127		beads, err := a.readBeadRows()
128		if err != nil {
129			return nil, err
130		}
131		events, err := a.readEventEntities()
132		if err != nil {
133			return nil, err
134		}
135		// Index beads by id so we can attach events and drop orphans.
136		byID := make(map[string]*Bead, len(beads))
137		for i := range beads {
138			byID[beads[i].ID] = &beads[i]
139		}
140		// Group events by bead id with exact per-bead capacity so the read path
141		// does not repeatedly grow slices while rebuilding the inline shape.
142		counts := make(map[string]int, len(events))
143		for _, ev := range events {
144			if _, ok := byID[ev.beadID]; !ok {
145				continue // orphan
146			}
147			counts[ev.beadID]++
148		}
149		grouped := make(map[string][]BeadEvent, len(counts))
150		for id, count := range counts {
151			grouped[id] = make([]BeadEvent, 0, count)
152		}
153		for _, ev := range events {
154			if _, ok := byID[ev.beadID]; !ok {
155				continue
156			}
157			grouped[ev.beadID] = append(grouped[ev.beadID], ev.event)
158		}
159		for id, evs := range grouped {
160			b := byID[id]
161			if b.Extra == nil {
162				b.Extra = make(map[string]any)
163			}
164			// Skip beads whose events have been externalised — the attachment file
165			// is the canonical source post-close and inlining stale events would
166			// duplicate the history.
167			if hasEventsAttachment(b) {
168				continue
169			}
170			b.Extra["events"] = encodeEventsForExtra(evs)
171		}
172		return beads, nil
173	}
