175	// WriteAll splits inline events from each bead and persists both collections.
176	// Writes are serialised at the directory-lock layer (WithLock); this method
177	// rewrites both files in temp+rename style so a crash mid-write leaves the
178	// previous snapshot intact rather than producing torn rows.
179	func (a *AxonBackend) WriteAll(beads []Bead) error {
180		if err := os.MkdirAll(a.Dir, 0o755); err != nil {
181			return fmt.Errorf("bead: axon mkdir: %w", err)
182		}
183		sort.Slice(beads, func(i, j int) bool { return beads[i].ID < beads[j].ID })
184	
185		var beadsBuf, eventsBuf bytes.Buffer
186		for _, b := range beads {
187			// Extract and strip inline events for the split.
188			var events []BeadEvent
189			if b.Extra != nil {
190				if raw, ok := b.Extra["events"]; ok {
191					events = decodeBeadEvents(raw)
192				}
193			}
194			stripped := beadWithoutInlineEvents(b)
195			row, err := axonEncodeBead(stripped)
196			if err != nil {
197				return fmt.Errorf("bead: axon marshal %s: %w", b.ID, err)
198			}
199			beadsBuf.Write(row)
200			beadsBuf.WriteByte('\n')
201	
202			for i, ev := range events {
203				data, err := axonEncodeEvent(b.ID, i, ev)
204				if err != nil {
205					return fmt.Errorf("bead: axon marshal event %s/%d: %w", b.ID, i, err)
206				}
207				eventsBuf.Write(data)
208				eventsBuf.WriteByte('\n')
209			}
210		}
211	
212		// Write events first so a crash between the two writes leaves orphan
213		// events (which ReadAll silently drops) rather than a bead row whose
214		// events have not landed yet — favouring the safer side of the partial-
215		// write window for an audit log.
216		if err := writeAtomicFile(a.EventsFile, eventsBuf.Bytes()); err != nil {
217			return fmt.Errorf("bead: axon write events: %w", err)
218		}
219		if err := writeAtomicFile(a.BeadsFile, beadsBuf.Bytes()); err != nil {
220			return fmt.Errorf("bead: axon write beads: %w", err)
221		}
222		return nil
223	}
