225	func (a *AxonBackend) WithLock(fn func() error) error {
226		wait := a.LockWait
227		if wait <= 0 {
228			wait = 10 * time.Second
229		}
230		if err := acquireDirLock(a.Dir, a.LockDir, wait); err != nil {
231			return err
232		}
233		defer os.RemoveAll(a.LockDir)
234		return fn()
235	}
