237	// beadWithoutInlineEvents returns a shallow copy of b whose Extra map omits
238	// the "events" key. The original Extra map is not mutated so callers can
239	// continue using the in-memory bead value after the split.
240	func beadWithoutInlineEvents(b Bead) Bead {
241		if b.Extra == nil {
242			return b
243		}
244		if _, ok := b.Extra["events"]; !ok {
245			return b
246		}
247		cp := make(map[string]any, len(b.Extra))
248		for k, v := range b.Extra {
249			if k == "events" {
250				continue
251			}
252			cp[k] = v
253		}
254		b.Extra = cp
255		return b
256	}
